import sys
import heapq
class Solution:
    def swimInWater(self, grid: list[list[int]]) -> bool:
        n = len(grid)
        visited = [[False]*n for _ in range(n)]
        pq = [(grid[0][0], 0, 0)]
        while pq:
            water_level, x, y = heapq.heappop(pq)
            if x == n-1 and y == n-1:
                return True
            if visited[x][y]:
                continue
            visited[x][y] = True
            for dx, dy in [(1, 0), (-1, 0), (0, 1), (0, -1)]:
                nx, ny = x + dx, y + dy
                if 0 <= nx < n and 0 <= ny < n and not visited[nx][ny]:
                    heapq.heappush(pq, (max(water_level, grid[nx][ny]), nx, ny))
        return False
if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        n = int(next(it))
        grid = [[int(next(it)) for _ in range(n)] for _ in range(n)]
    except StopIteration:
        sys.exit(0)
    sol = Solution()
    ans = sol.swimInWater(grid)
    print(str(ans).lower())

