#include <numeric>
#include <bits/stdc++.h>
using namespace std;
class Solution {
public:
    bool swimInWater(vector<vector<int>>& grid) {
        int n = grid.size();
        vector<vector<bool>> visited(n, vector<bool>(n, false));
        priority_queue<tuple<int, int, int>, vector<tuple<int, int, int>>, greater<tuple<int, int, int>>> pq;
        pq.emplace(grid[0][0], 0, 0);
        while (!pq.empty()) {
            auto _tmp_binding_1 = pq.top(); auto water_level = std::get<0>(_tmp_binding_1); auto x = std::get<1>(_tmp_binding_1); auto y = std::get<2>(_tmp_binding_1);
            pq.pop();
            if (x == n-1 && y == n-1)
                return true;
            if (visited[x][y])
                continue;
            visited[x][y] = true;
            vector<pair<int, int>> directions = {{1, 0}, {-1, 0}, {0, 1}, {0, -1}};
            for (auto _tmp_pair_0 : directions) { auto dx = _tmp_pair_0.first; auto dy = _tmp_pair_0.second;
                int nx = x + dx, ny = y + dy;
                if (0 <= nx && nx < n && 0 <= ny && ny < n && !visited[nx][ny])
                    pq.emplace(max(water_level, grid[nx][ny]), nx, ny);
            }
        }
        return false;
    }
};
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    vector<vector<int>> grid(n, vector<int>(n));
    for (int i = 0; i < n; i++)
        for (int j = 0; j < n; j++)
            cin >> grid[i][j];
    Solution sol;
    bool ans = sol.swimInWater(grid);
    cout << (ans ? "true" : "false") << "\n";
    return 0;
}
